        int totalFinedAmount = 0;
        int[] totalFirstTransferenceAmount = new int[thisYear - year + 1];
        int[] totalFirstTransferenceCount = new int[thisYear - year + 1];
        int[] totalFirstDebtObligationsAmount = new int[thisYear - year + 1];
