                    totalFinedAmount += Encoder.parseInt(entry.getFieldValue(FINED_AMOUNT_FIELD));
                    int[] ft = getFirstTransference(entry);
                    if (ft[0] >= year && ft[0] <= thisYear) {
                        totalFirstTransferenceAmount[ft[0] - year] += ft[1];
                        totalFirstTransferenceCount[ft[0] - year]++;
                    }

                    int[] fdo = getFirstDebtObligations(entry);
